mapper.select:
SELECT c.commitment_id, c.tenant_id, c.project_id, c.commitment_type, c.commitment_content, c.signature_image, c.sign_time, c.ip_address, c.device_info, c.status, c.create_by, c.create_time, c.update_by, c.update_time, c.remark, c.del_flag, u.nickname as user_nickname, u.phone as user_account, p.project_name, p.project_code FROM hz_commitment c LEFT JOIN hz_user u ON c.tenant_id = u.user_id LEFT JOIN hz_project p ON c.project_id = p.project_id WHERE c.del_flag = '0'
AND c.tenant_id = #{tenantId}
AND c.project_id = #{projectId}
AND c.commitment_type = #{commitmentType}
AND c.status = #{status}
AND DATE_FORMAT(c.sign_time, '%Y-%m-%d') >= DATE_FORMAT(#{params.beginTime}, '%Y-%m-%d')
AND DATE_FORMAT(c.sign_time, '%Y-%m-%d') <= DATE_FORMAT(#{params.endTime}, '%Y-%m-%d')
ORDER BY c.sign_time DESC
